brain:
if(Math.random()<0.5){context.action.desiredForce=context.state.maxForce;}
var s=context.state,a=context.action,m=context.memory;
var PI=Math.PI,PI2=PI*2;
if(!m.t){m.t=0;m.lf=-99;}m.t++;
var angDiff=function(x,y){var d=(x-y)%PI2;if(d>PI)d-=PI2;if(d<-PI)d+=PI2;return d;};
var closest=s.proximity[0]||{};
var front=s.scanner.robot[0]||false;
var eProj=s.scanner.projectile[0]||false;
var rem=context.round.remaining;
var myX=s.position.x,myY=s.position.y,myA=s.angle;
var dC=Math.sqrt((myX-450)*(myX-450)+(myY-450)*(myY-450));
var toC=s.angleToCenter;
var nearbot=false;
for(var j=0;j<s.proximity.length;j++){
  var p=s.proximity[j];
  if(p.entityType==='robot'&&p.range<55){nearbot=p;break;}
}
if(rem<5){
  if(dC>8){a.desiredAngle=toC;a.desiredForce=s.maxForce;}
  else a.desiredForce=0;
  if(nearbot){a.desiredAngle=(nearbot.angleFromRobot+PI)%PI2;a.desiredForce=s.maxForce*0.5;}
}else if(rem<12){
  a.desiredAngle=toC;a.desiredForce=s.maxForce;
  if(front&&front.active&&front.team!=s.team&&!nearbot){
    var r2=front.range,ps=42,tF2=r2/ps;
    var lx=front.x+front.speed*Math.cos(front.angle)*tF2;
    var ly=front.y+front.speed*Math.sin(front.angle)*tF2;
    var lA=Math.atan2(ly-myY,lx-myX);
    var ae=Math.abs(angDiff(myA,lA));
    if(ae<Math.atan2(28,r2)&&(m.t-m.lf)>=30){a.desiredLaunch=true;m.lf=m.t;}
  }
  if(nearbot){a.desiredAngle=(nearbot.angleFromRobot+PI)%PI2;a.desiredForce=s.maxForce*0.5;}
}else if(closest.entityType=="wall"){
  a.desiredAngle=toC;
}else if(front){
  if(front.active&&front.team!=s.team){
    if(!nearbot){
      var r1=front.range,ps1=42,tF1=r1/ps1;
      var lx1=front.x+front.speed*Math.cos(front.angle)*tF1;
      var ly1=front.y+front.speed*Math.sin(front.angle)*tF1;
      var lA1=Math.atan2(ly1-myY,lx1-myX);
      a.desiredAngle=lA1;
      var ae1=Math.abs(angDiff(myA,lA1));
      if(ae1<Math.atan2(28,r1)&&(m.t-m.lf)>=30){a.desiredLaunch=true;m.lf=m.t;}
    }
  }else{
    var dir2=(front.angleFromRobot-s.angle)<0?-1:1;
    a.desiredAngle=s.angle-(dir2*0.174533);
    a.desiredForce=s.maxForce/2;
  }
}else if(Math.random()<0.005){
  var maxvar=PI/4;
  a.desiredAngle=s.angle+(Math.random()*maxvar)-maxvar/2;
  a.desiredForce=0;
}
if(!nearbot&&eProj&&eProj.range<100){
  var inc=(eProj.angleFromRobot+PI)%PI2;
  var pD=Math.abs(angDiff(eProj.angle,inc));
  if(pD<0.5){
    var pL=eProj.angleFromRobot+PI/2;
    var pR=eProj.angleFromRobot-PI/2;
    var dL=Math.abs(angDiff(pL,toC));
    var dR=Math.abs(angDiff(pR,toC));
    a.desiredAngle=(dL<dR)?pL:pR;
    a.desiredForce=s.maxForce*0.6;
  }
}
if(nearbot&&rem>=5){a.desiredAngle=(nearbot.angleFromRobot+PI)%PI2;a.desiredForce=s.maxForce*0.5;}
